diff --git a/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp b/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp
index 524b268aee2f..97c7838e9e53 100644
--- a/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp
@@ -43,6 +43,32 @@

 using namespace llvm;

+static bool hasPotentiallyZeroDivisor(const SCEV *S, ScalarEvolution &SE) {
+  // Check if this SCEV node is a division (UDiv or SDiv)
+  if (const SCEVUDivExpr *UDiv = dyn_cast<SCEVUDivExpr>(S)) {
+    // Check if the divisor is known to be non-zero
+    if (!SE.isKnownNonZero(UDiv->getRHS())) {
+      return true;
+    }
+  }
+  if (const SCEVSDivExpr *SDiv = dyn_cast<SCEVSDivExpr>(S)) {
+    // Check if the divisor is known to be non-zero
+    if (!SE.isKnownNonZero(SDiv->getRHS())) {
+      return true;
+    }
+  }
+  
+  // Recursively check all operands
+  for (const SCEV *Op : S->operands()) {
+    if (hasPotentiallyZeroDivisor(Op, SE)) {
+      return true;
+    }
+  }
+  
+  return false;
+}
+
+
 #define DEBUG_TYPE "loop-unroll"

 STATISTIC(NumRuntimeUnrolled,
@@ -674,6 +700,14 @@ bool llvm::UnrollRuntimeLoopRemainder(
   BranchInst *PreHeaderBR = cast<BranchInst>(PreHeader->getTerminator());
   const DataLayout &DL = Header->getDataLayout();
   SCEVExpander Expander(*SE, DL, "loop-unroll");
+  // Check if expanding the trip count would cause undefined behavior due to
+  // division by potentially zero values.
+  if (hasPotentiallyZeroDivisor(TripCountSC, *SE)) {
+    LLVM_DEBUG(dbgs() << "Trip count SCEV has potentially zero divisor, skipping runtime unrolling.
+");
+    return false;
+  }
+
   if (!AllowExpensiveTripCount &&
       Expander.isHighCostExpansion(TripCountSC, L, SCEVExpansionBudget, TTI,
                                    PreHeaderBR)) {
